/* Local lightweight jQuery-compatible helper for this static coursework project. */
(function (global) {
  function toArray(value) { return Array.prototype.slice.call(value || []); }
  function JQ(nodes) { this.nodes = nodes; this.length = nodes.length; }
  JQ.prototype.each = function (callback) { this.nodes.forEach(function (el, i) { callback.call(el, i, el); }); return this; };
  JQ.prototype.val = function (value) {
    if (value === undefined) return this.nodes[0] ? this.nodes[0].value : '';
    return this.each(function () { this.value = value; });
  };
  JQ.prototype.text = function (value) {
    if (value === undefined) return this.nodes.map(function (el) { return el.textContent; }).join('');
    return this.each(function () { this.textContent = value; });
  };
  JQ.prototype.html = function (value) {
    if (value === undefined) return this.nodes[0] ? this.nodes[0].innerHTML : '';
    return this.each(function () { this.innerHTML = value; });
  };
  JQ.prototype.on = function (eventName, handler) { return this.each(function () { this.addEventListener(eventName, handler); }); };
  JQ.prototype.addClass = function (className) { return this.each(function () { this.classList.add(className); }); };
  JQ.prototype.removeClass = function (className) { return this.each(function () { this.classList.remove(className); }); };
  function $(selector) {
    if (typeof selector === 'function') {
      if (document.readyState !== 'loading') selector();
      else document.addEventListener('DOMContentLoaded', selector);
      return new JQ([]);
    }
    if (selector instanceof JQ) return selector;
    if (selector instanceof Element || selector === window || selector === document) return new JQ([selector]);
    return new JQ(toArray(document.querySelectorAll(selector)));
  }
  global.$ = global.jQuery = $;
})(window);
